      <div class="meta-item"><label>To</label><div>${escapeHtml(toText || 'N/A')}</div></div>
      <div class="meta-item"><label>Gmail ID</label><div>${escapeHtml(clean(result.id) || 'N/A')}</div></div>
      <div class="meta-item"><label>Message-ID</label><div>${escapeHtml(messageIdHeader || 'N/A')}</div></div>
      <div class="meta-item"><label>Thread ID</label><div>${escapeHtml(clean(result.threadId) || 'N/A')}</div></div>
      <div class="meta-item"><label>Labels</label><div>${escapeHtml(labelIds || 'N/A')}</div></div>
    </div></section>
    <section class="panel"><div class="email-body">${bodyHtml || '<p>No message body was returned.</p>'}</div></section>` : ''}
  </div>
</body>
</html>`;
return [{ json: { html } }];
